import React from 'react';
import { motion } from 'framer-motion';
import { PortfolioItemData } from '../../types';

interface PortfolioRowProps {
  category: string;
  items: PortfolioItemData[];
  speed?: number;
}

export const PortfolioRow: React.FC<PortfolioRowProps> = ({ category, items, speed = 60 }) => {
  // Triple the items to ensure smooth infinite loop
  // The animation moves -33.333% of the total width (which corresponds to one full set of items)
  const marqueeItems = [...items, ...items, ...items];

  return (
    <div className="py-12 border-b border-gray-100 last:border-none">
      <div className="px-6 md:px-10 mb-8 flex items-end justify-between">
        <h3 className="text-2xl md:text-3xl font-bold flex items-center gap-3 tracking-tight">
            <span className="w-2 h-2 md:w-3 md:h-3 bg-[#2563EB] rounded-full"></span>
            {category}
        </h3>
        <span className="text-xs font-bold text-gray-400 uppercase tracking-widest hidden md:block">
            {items.length} Projects
        </span>
      </div>

      <div className="overflow-hidden w-full">
        <motion.div 
          className="flex gap-6 md:gap-8 w-max"
          animate={{ x: "-33.333%" }}
          initial={{ x: "0%" }}
          transition={{ 
            repeat: Infinity, 
            ease: "linear", 
            duration: speed 
          }}
        >
          {marqueeItems.map((item, idx) => (
            <div key={`${item.title}-${idx}`} className="w-[80vw] md:w-[28rem] flex-shrink-0 group cursor-pointer">
              <div className="aspect-[16/10] bg-gray-100 mb-5 rounded-2xl overflow-hidden relative shadow-sm border border-gray-100">
                <img 
                  src={item.imageUrl} 
                  alt={item.title} 
                  className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700"
                />
                 <div className="absolute inset-0 bg-black/0 group-hover:bg-black/10 transition-colors duration-300"></div>
              </div>
              <h4 className="text-xl font-bold group-hover:text-[#2563EB] transition-colors px-1 leading-tight">{item.title}</h4>
              {item.desc && <p className="text-gray-500 text-sm mt-2 px-1">{item.desc}</p>}
            </div>
          ))}
        </motion.div>
      </div>
    </div>
  );
};

import React, { useRef } from 'react';
import { motion } from 'framer-motion';
import { ArrowLeft, ArrowRight } from 'lucide-react';
import { PortfolioItemData } from '../../types';

interface PortfolioRowProps {
  category: string;
  items: PortfolioItemData[];
}

export const PortfolioRow: React.FC<PortfolioRowProps> = ({ category, items }) => {
  const scrollContainerRef = useRef<HTMLDivElement>(null);

  const scroll = (direction: 'left' | 'right') => {
    if (scrollContainerRef.current) {
      // Scroll amount roughly equal to one item width + gap
      const scrollAmount = 440; 
      const container = scrollContainerRef.current;
      const targetScroll = direction === 'left' 
        ? container.scrollLeft - scrollAmount 
        : container.scrollLeft + scrollAmount;

      container.scrollTo({
        left: targetScroll,
        behavior: 'smooth'
      });
    }
  };

  return (
    <div className="py-12 border-b border-gray-100 last:border-none">
      <div className="px-6 md:px-10 mb-8 flex items-end justify-between">
        <h3 className="text-2xl md:text-3xl font-bold flex items-center gap-3 tracking-tight">
            <span className="w-2 h-2 md:w-3 md:h-3 bg-[#2563EB] rounded-full"></span>
            {category}
        </h3>

        {/* Navigation Buttons */}
        <div className="flex gap-2">
            <button 
                onClick={() => scroll('left')}
                className="p-3 rounded-full border border-gray-200 hover:bg-black hover:text-white hover:border-black transition-colors flex items-center justify-center"
                aria-label="Scroll left"
            >
                <ArrowLeft size={20} />
            </button>
            <button 
                onClick={() => scroll('right')}
                className="p-3 rounded-full border border-gray-200 hover:bg-black hover:text-white hover:border-black transition-colors flex items-center justify-center"
                aria-label="Scroll right"
            >
                <ArrowRight size={20} />
            </button>
        </div>
      </div>

      {/* Scrollable Container */}
      <div 
        ref={scrollContainerRef}
        className="flex overflow-x-auto gap-6 px-6 md:px-10 pb-8 snap-x snap-mandatory [&::-webkit-scrollbar]:hidden"
        style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}
      >
        {items.map((item, idx) => (
          <motion.div 
            key={`${item.title}-${idx}`} 
            initial={{ opacity: 0, x: 20 }}
            whileInView={{ opacity: 1, x: 0 }}
            viewport={{ once: true }}
            transition={{ delay: idx * 0.1, duration: 0.5 }}
            className="w-[85vw] md:w-[26rem] flex-shrink-0 snap-start group cursor-pointer"
          >
            <div className="aspect-[16/10] bg-gray-100 mb-5 rounded-2xl overflow-hidden relative shadow-sm border border-gray-100">
              <img 
                src={item.imageUrl} 
                alt={item.title} 
                className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700"
              />
               <div className="absolute inset-0 bg-black/0 group-hover:bg-black/10 transition-colors duration-300"></div>
            </div>
            <h4 className="text-xl font-bold group-hover:text-[#2563EB] transition-colors px-1 leading-tight">{item.title}</h4>
            {item.desc && <p className="text-gray-500 text-sm mt-2 px-1">{item.desc}</p>}
          </motion.div>
        ))}
        {/* Spacer to ensure the last item has right padding when scrolled */}
        <div className="w-1 md:w-4 flex-shrink-0" />
      </div>
    </div>
  );
};

import React, { useRef } from 'react';
import { motion } from 'framer-motion';
import { ArrowLeft, ArrowRight } from 'lucide-react';
import { PortfolioItemData } from '../../types';

interface PortfolioRowProps {
  category: string;
  items: PortfolioItemData[];
}

export const PortfolioRow: React.FC<PortfolioRowProps> = ({ category, items }) => {
  const scrollContainerRef = useRef<HTMLDivElement>(null);

  // Scroll by button (approx one screen width or item set)
  const scroll = (direction: 'left' | 'right') => {
    if (scrollContainerRef.current) {
      const scrollAmount = 400; 
      const container = scrollContainerRef.current;
      const targetScroll = direction === 'left' 
        ? container.scrollLeft - scrollAmount 
        : container.scrollLeft + scrollAmount;

      container.scrollTo({
        left: targetScroll,
        behavior: 'smooth'
      });
    }
  };

  // Scroll specific item into view when clicked
  const handleItemClick = (index: number) => {
    if (scrollContainerRef.current) {
      const container = scrollContainerRef.current;
      const children = container.children;
      const target = children[index] as HTMLElement;

      if (target) {
        // Calculate position to center or align left. 
        // We align left with a bit of padding offset to match the container's padding.
        // Desktop padding is px-10 (2.5rem = 40px), Mobile is px-6 (1.5rem = 24px)
        const paddingOffset = window.innerWidth >= 768 ? 40 : 24;

        container.scrollTo({
          left: target.offsetLeft - paddingOffset,
          behavior: 'smooth'
        });
      }
    }
  };

