  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const [isPaused, setIsPaused] = useState(false);

  // Duplicate items to create an infinite scrolling effect (buffer)
  // We use 3 sets to ensure smooth looping
  const displayItems = [...items, ...items, ...items];

  // Auto-scroll logic
  useEffect(() => {
    const container = scrollContainerRef.current;
    if (!container) return;

    let animationFrameId: number;
    // Speed of auto-scroll (higher = faster)
    const speed = 1.2; 

    const animate = () => {
      if (!isPaused && container) {
        container.scrollLeft += speed;

        // Infinite Loop Logic:
        // If we've scrolled past the first set of items (approx 1/3 of scrollWidth),
        // reset to 0 to create seamless loop.
        // Note: This assumes items have roughly equal total width. 
        // A safer check is comparing scrollLeft to scrollWidth / 3
        if (container.scrollLeft >= container.scrollWidth / 3) {
          container.scrollLeft = 0;
        }
      }
      animationFrameId = requestAnimationFrame(animate);
    };

    animationFrameId = requestAnimationFrame(animate);

    return () => cancelAnimationFrame(animationFrameId);
  }, [isPaused, items.length]);

  // Manual scroll by button
  const scroll = (direction: 'left' | 'right') => {
    if (scrollContainerRef.current) {
      const scrollAmount = 450; 
      const container = scrollContainerRef.current;

      // Calculate target
      const targetScroll = direction === 'left' 
        ? container.scrollLeft - scrollAmount 
        : container.scrollLeft + scrollAmount;

      container.scrollTo({
        left: targetScroll,
        behavior: 'smooth'
      });
    }
  };

  // Scroll specific item into view when clicked
  const handleItemClick = (index: number) => {
    if (scrollContainerRef.current) {
      const container = scrollContainerRef.current;
      const children = container.children;
      // Because we tripled the items, the clicked index in the DOM matches the map index
      const target = children[index] as HTMLElement;

      if (target) {
        const paddingOffset = window.innerWidth >= 768 ? 40 : 24;
        container.scrollTo({
          left: target.offsetLeft - paddingOffset,
          behavior: 'smooth'
        });
      }
    }
  };

  return (
    <div 
      className="py-12 border-b border-gray-100 last:border-none"
      onMouseEnter={() => setIsPaused(true)}
      onMouseLeave={() => setIsPaused(false)}
